class _UniffiFfiConverterString:
    @staticmethod
    def check_lower(value):
        if not isinstance(value, str):
            raise TypeError("argument must be str, not {}".format(type(value).__name__))
        return value

    @staticmethod
    def read(buf):
        size = buf.read_i32()
        if size < 0:
            raise InternalError("Unexpected negative string length")
        utf8_bytes = buf.read(size)
        return utf8_bytes.decode("utf-8")

    @staticmethod
    def write(value, buf):
        utf8_bytes = value.encode("utf-8")
        buf.write_i32(len(utf8_bytes))
        buf.write(utf8_bytes)

    @staticmethod
    def lift(buf):
        with buf.consume_with_stream() as stream:
            return stream.read(stream.remaining()).decode("utf-8")

    @staticmethod
    def lower(value):
        with _UniffiRustBuffer.alloc_with_builder() as builder:
            builder.write(value.encode("utf-8"))
            return builder.finalize()



# SwitchboardError
# We want to define each variant as a nested class that's also a subclass,
# which is tricky in Python.  To accomplish this we're going to create each
# class separately, then manually add the child classes to the base class's
# __dict__.  All of this happens in dummy class to avoid polluting the module
# namespace.
class SwitchboardError(Exception):
    """
    Errors returned by the switchboard orchestrator.
"""
    pass

_UniffiTempSwitchboardError = SwitchboardError

class SwitchboardError:  # type: ignore
    """
    Errors returned by the switchboard orchestrator.
"""
    
    class InvalidProcessorName(_UniffiTempSwitchboardError):
        """
        Processor names must be non-empty.
"""
        
        def __init__(self):
            pass

        def __repr__(self):
            return "SwitchboardError.InvalidProcessorName({})".format(str(self))
    _UniffiTempSwitchboardError.InvalidProcessorName = InvalidProcessorName # type: ignore
    class ProcessorAlreadyRegistered(_UniffiTempSwitchboardError):
        """
        Registering a duplicate processor name is rejected.
"""
        
        def __init__(self, name):
            super().__init__(", ".join([
                "name={!r}".format(name),
            ]))
            self.name = name

        def __repr__(self):
            return "SwitchboardError.ProcessorAlreadyRegistered({})".format(str(self))
    _UniffiTempSwitchboardError.ProcessorAlreadyRegistered = ProcessorAlreadyRegistered # type: ignore
    class ProcessorNotFound(_UniffiTempSwitchboardError):
        """
        A requested processor name was not registered.
"""
        
        def __init__(self, name):
            super().__init__(", ".join([
                "name={!r}".format(name),
            ]))
            self.name = name

        def __repr__(self):
            return "SwitchboardError.ProcessorNotFound({})".format(str(self))
    _UniffiTempSwitchboardError.ProcessorNotFound = ProcessorNotFound # type: ignore
    class UnexpectedUniFfiCallback(_UniffiTempSwitchboardError):
        """
        Unexpected callback errors from UniFFI are surfaced explicitly.
"""
        
        def __init__(self, reason):
            super().__init__(", ".join([
                "reason={!r}".format(reason),
            ]))
            self.reason = reason

        def __repr__(self):
            return "SwitchboardError.UnexpectedUniFfiCallback({})".format(str(self))
    _UniffiTempSwitchboardError.UnexpectedUniFfiCallback = UnexpectedUniFfiCallback # type: ignore

SwitchboardError = _UniffiTempSwitchboardError # type: ignore
del _UniffiTempSwitchboardError


class _UniffiFfiConverterTypeSwitchboardError(_UniffiConverterRustBuffer):
    @staticmethod
    def read(buf):
        variant = buf.read_i32()
        if variant == 1:
            return SwitchboardError.InvalidProcessorName(
            )
        if variant == 2:
            return SwitchboardError.ProcessorAlreadyRegistered(
                _UniffiFfiConverterString.read(buf),
            )
        if variant == 3:
            return SwitchboardError.ProcessorNotFound(
                _UniffiFfiConverterString.read(buf),
            )
        if variant == 4:
            return SwitchboardError.UnexpectedUniFfiCallback(
                _UniffiFfiConverterString.read(buf),
            )
        raise InternalError("Raw enum value doesn't match any cases")

    @staticmethod
    def check_lower(value):
        if isinstance(value, SwitchboardError.InvalidProcessorName):
            return
        if isinstance(value, SwitchboardError.ProcessorAlreadyRegistered):
            _UniffiFfiConverterString.check_lower(value.name)
            return
        if isinstance(value, SwitchboardError.ProcessorNotFound):
            _UniffiFfiConverterString.check_lower(value.name)
            return
        if isinstance(value, SwitchboardError.UnexpectedUniFfiCallback):
            _UniffiFfiConverterString.check_lower(value.reason)
            return

    @staticmethod
    def write(value, buf):
        if isinstance(value, SwitchboardError.InvalidProcessorName):
            buf.write_i32(1)
        if isinstance(value, SwitchboardError.ProcessorAlreadyRegistered):
            buf.write_i32(2)
            _UniffiFfiConverterString.write(value.name, buf)
        if isinstance(value, SwitchboardError.ProcessorNotFound):
            buf.write_i32(3)
            _UniffiFfiConverterString.write(value.name, buf)
        if isinstance(value, SwitchboardError.UnexpectedUniFfiCallback):
            buf.write_i32(4)
            _UniffiFfiConverterString.write(value.reason, buf)


class ProcessorRegistrationProtocol(typing.Protocol):
    """
    Opaque registration handle that adapts a concrete processor into the switchboard registry.
"""
    
    pass

class ProcessorRegistration(ProcessorRegistrationProtocol):
    """
    Opaque registration handle that adapts a concrete processor into the switchboard registry.
"""
    
    _handle: ctypes.c_uint64
    
    def __init__(self, *args, **kwargs):
        raise ValueError("This class has no default constructor")

    def __del__(self):
        # In case of partial initialization of instances.
        handle = getattr(self, "_handle", None)
        if handle is not None:
            _uniffi_rust_call(_UniffiLib.uniffi_switchboard_fn_free_processorregistration, handle)

    def _uniffi_clone_handle(self):
        return _uniffi_rust_call(_UniffiLib.uniffi_switchboard_fn_clone_processorregistration, self._handle)

    # Used by alternative constructors or any methods which return this type.
    @classmethod
    def _uniffi_make_instance(cls, handle):
        # Lightly yucky way to bypass the usual __init__ logic
        # and just create a new instance with the required handle.
        inst = cls.__new__(cls)
        inst._handle = handle
        return inst





class _UniffiFfiConverterTypeProcessorRegistration:
    @staticmethod
    def lift(value: int) -> ProcessorRegistration:
        return ProcessorRegistration._uniffi_make_instance(value)

    @staticmethod
    def check_lower(value: ProcessorRegistration):
        if not isinstance(value, ProcessorRegistration):
            raise TypeError("Expected ProcessorRegistration instance, {} found".format(type(value).__name__))

    @staticmethod
    def lower(value: ProcessorRegistration) -> ctypes.c_uint64:
        return value._uniffi_clone_handle()

    @classmethod
    def read(cls, buf: _UniffiRustBuffer) -> ProcessorRegistration:
        ptr = buf.read_u64()
        if ptr == 0:
            raise InternalError("Raw handle value was null")
        return cls.lift(ptr)

    @classmethod
    def write(cls, value: ProcessorRegistration, buf: _UniffiRustBuffer):
        buf.write_u64(cls.lower(value))

class _UniffiFfiConverterSequenceString(_UniffiConverterRustBuffer):
    @classmethod
    def check_lower(cls, value):
        for item in value:
            _UniffiFfiConverterString.check_lower(item)

    @classmethod
    def write(cls, value, buf):
        items = len(value)
        buf.write_i32(items)
        for item in value:
            _UniffiFfiConverterString.write(item, buf)

    @classmethod
    def read(cls, buf):
        count = buf.read_i32()
        if count < 0:
            raise InternalError("Unexpected negative sequence length")

        return [
            _UniffiFfiConverterString.read(buf) for i in range(count)
        ]


class SwitchboardProtocol(typing.Protocol):
    """
    Registry and dispatcher for named processors.
"""
    
    def available_processors(self, ) -> typing.List[str]:
        """
        Returns all registered processor names in sorted order.
"""
        raise NotImplementedError
    async def process_with(self, name: str,request_json: str) -> str:
        """
        Dispatches a JSON request to the selected processor.

        # Errors

        Returns an error if the processor is unknown or its callback fails.
"""
        raise NotImplementedError
    def register_processor(self, name: str,processor: ProcessorRegistration) -> None:
        """
        Registers a named processor implementation.

        # Errors

        Returns an error if the name is blank or already registered.
"""
        raise NotImplementedError

class Switchboard(SwitchboardProtocol):
    """
    Registry and dispatcher for named processors.
"""
    
    _handle: ctypes.c_uint64
    def __init__(self, ):
        """
        Creates an empty switchboard.
"""
        _uniffi_lowered_args = (
        )
        _uniffi_lift_return = _UniffiFfiConverterTypeSwitchboard.lift
        _uniffi_error_converter = None
        _uniffi_ffi_result = _uniffi_rust_call_with_error(
            _uniffi_error_converter,
            _UniffiLib.uniffi_switchboard_fn_constructor_switchboard_new,
            *_uniffi_lowered_args,
        )
        self._handle = _uniffi_ffi_result

    def __del__(self):
        # In case of partial initialization of instances.
        handle = getattr(self, "_handle", None)
        if handle is not None:
            _uniffi_rust_call(_UniffiLib.uniffi_switchboard_fn_free_switchboard, handle)

    def _uniffi_clone_handle(self):
        return _uniffi_rust_call(_UniffiLib.uniffi_switchboard_fn_clone_switchboard, self._handle)

    # Used by alternative constructors or any methods which return this type.
    @classmethod
    def _uniffi_make_instance(cls, handle):
        # Lightly yucky way to bypass the usual __init__ logic
        # and just create a new instance with the required handle.
        inst = cls.__new__(cls)
        inst._handle = handle
        return inst
    def available_processors(self, ) -> typing.List[str]:
        """
        Returns all registered processor names in sorted order.
"""
        _uniffi_lowered_args = (
            self._uniffi_clone_handle(),
        )
        _uniffi_lift_return = _UniffiFfiConverterSequenceString.lift
        _uniffi_error_converter = None
        _uniffi_ffi_result = _uniffi_rust_call_with_error(
            _uniffi_error_converter,
            _UniffiLib.uniffi_switchboard_fn_method_switchboard_available_processors,
            *_uniffi_lowered_args,
        )
        return _uniffi_lift_return(_uniffi_ffi_result)
    async def process_with(self, name: str,request_json: str) -> str:
        """
        Dispatches a JSON request to the selected processor.

        # Errors

        Returns an error if the processor is unknown or its callback fails.
"""
        
        _UniffiFfiConverterString.check_lower(name)

        _UniffiFfiConverterString.check_lower(request_json)
        _uniffi_lowered_args = (
            self._uniffi_clone_handle(),
            _UniffiFfiConverterString.lower(name),
            _UniffiFfiConverterString.lower(request_json),
        )
        _uniffi_lift_return = _UniffiFfiConverterString.lift
        _uniffi_error_converter = _UniffiFfiConverterTypeSwitchboardError
        return await _uniffi_rust_call_async(
            _UniffiLib.uniffi_switchboard_fn_method_switchboard_process_with(*_uniffi_lowered_args),
            _UniffiLib.ffi_switchboard_rust_future_poll_rust_buffer,
            _UniffiLib.ffi_switchboard_rust_future_complete_rust_buffer,
            _UniffiLib.ffi_switchboard_rust_future_free_rust_buffer,
            _uniffi_lift_return,
            _uniffi_error_converter,
        )
    def register_processor(self, name: str,processor: ProcessorRegistration) -> None:
        """
        Registers a named processor implementation.

        # Errors

        Returns an error if the name is blank or already registered.
"""
        
        _UniffiFfiConverterString.check_lower(name)

        _UniffiFfiConverterTypeProcessorRegistration.check_lower(processor)
        _uniffi_lowered_args = (
            self._uniffi_clone_handle(),
            _UniffiFfiConverterString.lower(name),
            _UniffiFfiConverterTypeProcessorRegistration.lower(processor),
        )
        _uniffi_lift_return = lambda val: None
        _uniffi_error_converter = _UniffiFfiConverterTypeSwitchboardError
        _uniffi_ffi_result = _uniffi_rust_call_with_error(
            _uniffi_error_converter,
            _UniffiLib.uniffi_switchboard_fn_method_switchboard_register_processor,
            *_uniffi_lowered_args,
        )
        return _uniffi_lift_return(_uniffi_ffi_result)





class _UniffiFfiConverterTypeSwitchboard:
    @staticmethod
    def lift(value: int) -> Switchboard:
        return Switchboard._uniffi_make_instance(value)

    @staticmethod
    def check_lower(value: Switchboard):
        if not isinstance(value, Switchboard):
            raise TypeError("Expected Switchboard instance, {} found".format(type(value).__name__))

    @staticmethod
    def lower(value: Switchboard) -> ctypes.c_uint64:
        return value._uniffi_clone_handle()

